@app.route('/cache/clear', methods=['POST'])
def clear_cache():
    data = request.get_json()
    pattern = data.get('pattern', '*')
    invalidate_cache(pattern)
    
    return jsonify({'status': 'success', 'message': f'Cache cleared for pattern: {pattern}'})


