@app.route('/session/count', methods=['GET'])
def session_count():
    pattern = f"{SESSION_PREFIX}*"
    keys = redis_client.keys(pattern)
    
    return jsonify({'active_sessions': len(keys)})


@app.route('/set_value', methods=['POST'])
def set_value():
    data = request.get_json()
    key = data.get('key')
    value = data.get('value')
    expiration = data.get('expiration', 3600)
    
    if key and value:
        redis_client.setex(f"custom:{key}", expiration, json.dumps(value))
        return jsonify({'status': 'success', 'message': 'Value set successfully'})
    
    return jsonify({'status': 'error', 'message': 'Invalid key or value'}), 400


@app.route('/get_value/<key>', methods=['GET'])
def get_value(key):
    value = redis_client.get(f"custom:{key}")
    
    if value:
        return jsonify({'key': key, 'value': json.loads(value)})
    
    return jsonify({'status': 'error', 'message': 'Key not found'}), 404


@app.route('/health', methods=['GET'])
def health():
    try:
        redis_client.ping()
        return jsonify({'status': 'healthy', 'redis': 'connected'})
    except redis.ConnectionError:
        return jsonify({'status': 'unhealthy', 'redis': 'disconnected'}), 503


